import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.security.InvalidKeyException;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;
import java.util.UUID;

public class FindAllBalance {
    private static final String ENDPOINT = "https://api.coinone.co.kr/v2.1/account/balance/all";
    private static final String ACCESS_TOKEN = "{accessToken}";
    private static final String SECRET_KEY = "{secretKey}";
    private static final ObjectMapper om = new ObjectMapper();

    record Payload(String access_token, String nonce){}

    public static void main(String[] args) {
        var nonce = UUID.randomUUID().toString();
        var payload = new Payload(ACCESS_TOKEN, nonce);
        var base64EncodedPayload = makeBase64EncodedPayload(payload);
        var signature = makeSignature(base64EncodedPayload);


        try {
            var client = HttpClient.newBuilder().build();
            var body = om.writeValueAsString(payload);
            var request = HttpRequest.newBuilder()
                    .uri(URI.create(ENDPOINT))
                    .header("Content-type", "application/json")
                    .header("X-COINONE-PAYLOAD", base64EncodedPayload)
                    .header("X-COINONE-SIGNATURE", signature)
                    .POST(HttpRequest.BodyPublishers.ofString(body))
                    .build();
            var response = client.send(request, HttpResponse.BodyHandlers.ofString());
            System.out.println(response.body());
        } catch (InterruptedException | IOException e) {
            throw new RuntimeException(e);
        }
    }

    private static String makeBase64EncodedPayload(Payload payload) {
        try {
            var bytesPayload = om.writeValueAsBytes(payload);
            return Base64.getEncoder().encodeToString(bytesPayload);
        } catch (JsonProcessingException e) {
            throw new RuntimeException(e);
        }
    }
    private static String makeSignature(String base64EncodedPayload) {
        try {
            var mac = Mac.getInstance("HmacSHA512");
            var keySpec = new SecretKeySpec(SECRET_KEY.getBytes(), "HmacSHA512");
            mac.init(keySpec);
            var messageDigest = mac.doFinal(base64EncodedPayload.getBytes());
            var sb = new StringBuilder();
            for (byte b : messageDigest) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();
        } catch (NoSuchAlgorithmException | InvalidKeyException e) {
            throw new RuntimeException(e);
        }
    }
}

