package main

import (
	"fmt"
)

import (
	"crypto/hmac"
	"crypto/sha512"
	"encoding/base64"
	"encoding/json"
	"github.com/google/uuid"
	"io"
	"net/http"
	"strings"
)

const (
	accessToken = "{access token}"
	secretKey   = "{secret key}"
)

func getEncodedPayload(payload map[string]interface{}) string {
	payload["nonce"] = uuid.New().String()

	dumpedJSON, _ := json.Marshal(payload)
	return base64.StdEncoding.EncodeToString(dumpedJSON)
}

func getSignature(encodedPayload string) string {
	h := hmac.New(sha512.New, []byte(secretKey))
	h.Write([]byte(encodedPayload))
	return fmt.Sprintf("%x", h.Sum(nil))
}

func getResponse(action string, payload map[string]interface{}) ([]byte, error) {
	url := fmt.Sprintf("https://api.coinone.co.kr%s", action)

	encodedPayload := getEncodedPayload(payload)

	req, err := http.NewRequest("POST", url, strings.NewReader(""))
	if err != nil {
		return nil, err
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("X-COINONE-PAYLOAD", encodedPayload)
	req.Header.Set("X-COINONE-SIGNATURE", getSignature(encodedPayload))

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}

	return body, nil
}

func main() {
	response, err := getResponse("/v2.1/account/balance/all", map[string]interface{}{
		"access_token": accessToken,
	})
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Println(string(response))
}

