public class FindTradeFeeByTradePair {
    private static final String ENDPOINT = "https://api.coinone.co.kr/v2.1/account/trade_fee/{quoteCurrency}/{targetCurrency}";
    private static final String ACCESS_TOKEN = "{accessToken}";
    private static final String SECRET_KEY = "{secretKey}";
    private static final ObjectMapper om = new ObjectMapper();

    record Payload(String access_token, String nonce){}

